  1	import { type FC, useContext, useMemo } from 'react';
  2	import { Link, useNavigate } from 'react-router-dom-v5-compat';
  3	import migrationIcon from 'src/components/images/resources/migration.svg';
  4	import providerTypes from 'src/modules/Plans/views/create/constanats/providerTypes';
  5	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  6	import { CreateOverviewContext } from 'src/overview/hooks/OverviewContext';
  7	import { useIsDarkTheme } from 'src/utils/hooks/useIsDarkTheme';
  8	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
  9	
 10	import { getImages } from '@components/images/logos';
 11	import { ProviderModelRef } from '@kubev2v/types';
 12	import { useActiveNamespace, useFlag } from '@openshift-console/dynamic-plugin-sdk';
 13	import {
 14	  Card,
 15	  CardBody,
 16	  ExpandableSection,
 17	  Flex,
 18	  FlexItem,
 19	  Split,
 20	  SplitItem,
 21	  Text,
 22	  TextContent,
 23	  TextVariants,
 24	  Tile,
 25	} from '@patternfly/react-core';
 26	import { type ProviderType, TELEMETRY_EVENTS } from '@utils/analytics/constants';
 27	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
 28	import { Namespace } from '@utils/constants';
 29	
 30	const WelcomeCard: FC = () => {
 31	  const { t } = useForkliftTranslation();
 32	  const { trackEvent } = useForkliftAnalytics();
 33	  const navigate = useNavigate();
 34	  const isDarkTheme = useIsDarkTheme();
 35	  const { data: { hideWelcomeCardByContext } = {}, setData } = useContext(CreateOverviewContext);
 36	  const providerItems = providerTypes(isDarkTheme);
 37	  const images = getImages(isDarkTheme);
 38	
 39	  const providersListUrl = useMemo(() => {
 40	    return getResourceUrl({
 41	      namespaced: false,
 42	      reference: ProviderModelRef,
 43	    });
 44	  }, []);
 45	  const providersCreateUrl = `${providersListUrl}/~new`;
 46	
 47	  const navigateToProvider = (type: ProviderType) => {
 48	    trackEvent(TELEMETRY_EVENTS.OVERVIEW_WELCOME_PROVIDER_CLICKED, {
 49	      providerType: type,
 50	    });
 51	    navigate(`${providersCreateUrl}?providerType=${type}`, {
 52	      state: { providerType: type as keyof typeof providerItems },
 53	    });
 54	  };
 55	  const [activeNamespace] = useActiveNamespace();
 56	  const kubevirtInstalled = useFlag('KUBEVIRT_DYNAMIC');
 57	  const namespaceURL =
 58	    activeNamespace === Namespace.AllProjects ? 'all-namespaces' : `ns/${activeNamespace}`;
 59	
 60	  const operatorHubURL = `/operatorhub/${namespaceURL}?keyword=kubevirt`;
 61	  const virtualizationOverviewURL = `/k8s/${namespaceURL}/virtualization-overview`;
 62	  return (
 63	    <Card>
 64	      <CardBody>
 65	        <ExpandableSection
 66	          toggleContent={
 67	            <TextContent>
 68	              <Text component={TextVariants.h3}>{t('Welcome')}</Text>
 69	            </TextContent>
 70	          }
 71	          isExpanded={!hideWelcomeCardByContext}
 72	          onToggle={(_ev, isExpanded) => {
 73	            setData({ hideWelcomeCardByContext: !isExpanded });
 74	          }}
 75	        >
 76	          <Split>
 77	            <SplitItem className="forklift-overview__welcome-left">
 78	              <img alt="" src={migrationIcon} />
 79	            </SplitItem>
 80	            <SplitItem className="forklift-overview__welcome-right">
 81	              <Flex direction={{ default: 'column' }} spacer={{ default: 'spacerMd' }}>
 82	                <FlexItem>
 83	                  <Text className="forklift-overview__welcome-text">
 84	                    <ForkliftTrans>
 85	                      Migration Toolkit for Virtualization (MTV) migrates virtual machines at scale
 86	                      to{' '}
 87	                      <Link to={kubevirtInstalled ? virtualizationOverviewURL : operatorHubURL}>
 88	                        Red Hat OpenShift Virtualization
 89	                      </Link>
 90	                      . This allows organizations to more easily access workloads running on virtual
 91	                      machines while developing new cloud-native applications.
 92	                    </ForkliftTrans>
 93	                  </Text>
 94	                </FlexItem>
 95	                <FlexItem>
 96	                  <Text className="forklift-overview__welcome-text">
 97	                    <ForkliftTrans>You can migrate virtual machines from:</ForkliftTrans>
 98	                  </Text>
 99	                </FlexItem>
100	                <FlexItem>
101	                  <div className="forklift-overview__welcome-tiles">
102	                    <Tile
103	                      className="vmware-tile"
104	                      title={providerItems.vsphere.title}
105	                      icon={<img alt="" src={images.vmwareImg} />}
106	                      onClick={() => {
107	                        navigateToProvider(providerItems.vsphere.key);
108	                      }}
109	                    />
110	                    <Tile
111	                      title={providerItems.ova.title}
112	                      icon={<img alt="" src={images.ovaImg} />}
113	                      onClick={() => {
114	                        navigateToProvider(providerItems.ova.key);
115	                      }}
116	                    />
117	                    <Tile
118	                      title={providerItems.openstack.title}
119	                      icon={<img alt="" src={images.openstackImg} />}
120	                      onClick={() => {
121	                        navigateToProvider(providerItems.openstack.key);
122	                      }}
123	                    />
124	                    <Tile
125	                      title={providerItems.ovirt.title}
126	                      icon={<img alt="" src={images.redhatImg} />}
127	                      onClick={() => {
128	                        navigateToProvider(providerItems.ovirt.key);
129	                      }}
130	                    />
131	                    <Tile
132	                      title={providerItems.openshift.title}
133	                      icon={<img alt="" src={images.openshiftImg} />}
134	                      onClick={() => {
135	                        navigateToProvider(providerItems.openshift.key);
136	                      }}
137	                    />
138	                  </div>
139	                </FlexItem>
140	              </Flex>
141	            </SplitItem>
142	          </Split>
143	        </ExpandableSection>
144	      </CardBody>
145	    </Card>
146	  );
147	};
148	
149	export default WelcomeCard;

